from pydantic_ai.durable_exec.temporal import TemporalRunContext

class MyRunContext(TemporalRunContext):
    @classmethod
    def serialize_run_context(cls, ctx: RunContext) -> dict:
        # 添加自定义属性到序列化结果
        data = super().serialize_run_context(ctx)
        data['custom_field'] = ctx.deps.some_field
        return data

    @classmethod
    def deserialize_run_context(cls, data: dict, **kwargs) -> 'MyRunContext':
        # 反序列化时重建完整上下文
        return super().deserialize_run_context(data, **kwargs)
